<script setup lang="ts">
/**
 * iOS Style Card Component
 * iOS 风格卡片组件（可折叠）
 */
import { ref, watch } from 'vue';

const props = withDefaults(
  defineProps<{
    title?: string;
    icon?: string;
    iconColor?: string;
    collapsible?: boolean;
    defaultExpanded?: boolean;
    hideHeader?: boolean;
  }>(),
  {
    title: undefined,
    icon: undefined,
    collapsible: true,
    defaultExpanded: false,
    hideHeader: false,
    iconColor: '#0a84ff',
  },
);

const emit = defineEmits<{
  (e: 'toggle', expanded: boolean): void;
}>();

const expanded = ref(props.defaultExpanded);

watch(
  () => props.defaultExpanded,
  val => {
    expanded.value = val;
  },
);

const toggleExpanded = () => {
  if (props.collapsible) {
    expanded.value = !expanded.value;
    emit('toggle', expanded.value);
  }
};

defineExpose({
  expand: () => (expanded.value = true),
  collapse: () => (expanded.value = false),
  toggle: toggleExpanded,
  isExpanded: () => expanded.value,
});
</script>

<template>
  <div class="ios-card" :class="{ 'ios-card-expanded': expanded, 'ios-card-bare': hideHeader }">
    <div
      v-if="!hideHeader"
      class="ios-card-header"
      :class="{ 'ios-card-header-clickable': collapsible }"
      @click="toggleExpanded"
    >
      <h4 class="ios-card-title">
        <i v-if="icon" :class="icon" :style="{ color: iconColor }"></i>
        <slot name="title">{{ title }}</slot>
      </h4>
      <div class="ios-card-header-right">
        <slot name="header-right"></slot>
        <i
          v-if="collapsible"
          :class="expanded ? 'fa-solid fa-chevron-up' : 'fa-solid fa-chevron-down'"
          class="ios-card-chevron"
        ></i>
      </div>
    </div>
    <transition name="ios-card-content">
      <div v-show="!collapsible || expanded" class="ios-card-content">
        <slot></slot>
      </div>
    </transition>
  </div>
</template>

