<script setup lang="ts">
/**
 * iOS Style Button Component
 * iOS 风格按钮组件
 *
 * 重要：样式全部使用内联 style（:style），不依赖 <style scoped>。
 * 原因：scoped 样式会被编译进 dist/style.css，而 style.css 在酒馆运行环境
 * 存在缓存/加载不生效的问题，会导致按钮丢失背景/内边距/圆角等基础样式。
 * 内联样式随组件 JS 一起注入，始终可靠。
 */
import { computed, ref } from 'vue';

const props = withDefaults(
  defineProps<{
    variant?: 'primary' | 'secondary' | 'success' | 'danger';
    size?: 'sm' | 'md' | 'lg';
    disabled?: boolean;
    loading?: boolean;
    icon?: string;
  }>(),
  {
    variant: 'secondary',
    size: 'md',
    disabled: false,
    loading: false,
    icon: undefined,
  },
);

const emit = defineEmits<{
  (e: 'click', event: MouseEvent): void;
}>();

const isHover = ref(false);
const isActive = ref(false);

const VARIANTS: Record<string, { bg: string; bgHover: string; color: string; border: string }> = {
  primary: { bg: '#0a84ff', bgHover: '#409cff', color: '#ffffff', border: 'none' },
  secondary: {
    bg: '#3a3a3c',
    bgHover: '#48484a',
    color: '#ffffff',
    border: '1px solid rgba(84, 84, 88, 0.4)',
  },
  success: { bg: '#30d158', bgHover: '#50e178', color: '#ffffff', border: 'none' },
  danger: { bg: '#ff453a', bgHover: '#ff6a61', color: '#ffffff', border: 'none' },
};

const SIZES: Record<string, { padding: string; fontSize: string; borderRadius: string }> = {
  sm: { padding: '8px 14px', fontSize: '13px', borderRadius: '8px' },
  md: { padding: '12px 20px', fontSize: '15px', borderRadius: '12px' },
  lg: { padding: '16px 28px', fontSize: '17px', borderRadius: '16px' },
};

const buttonStyle = computed(() => {
  const v = VARIANTS[props.variant] || VARIANTS.secondary;
  const s = SIZES[props.size] || SIZES.md;
  const isDisabled = props.disabled || props.loading;
  const hovering = isHover.value && !isDisabled;

  return {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '8px',
    padding: s.padding,
    fontSize: s.fontSize,
    fontWeight: '500',
    borderRadius: s.borderRadius,
    border: v.border,
    background: hovering ? v.bgHover : v.bg,
    color: v.color,
    cursor: isDisabled ? 'not-allowed' : 'pointer',
    opacity: isDisabled ? '0.5' : '1',
    transition: 'all 0.25s ease',
    transform: isActive.value && !isDisabled ? 'scale(0.98)' : 'none',
    lineHeight: '1.2',
    whiteSpace: 'nowrap',
    WebkitTapHighlightColor: 'transparent',
    userSelect: 'none',
  } as Record<string, string>;
});

const handleClick = (event: MouseEvent) => {
  if (!props.disabled && !props.loading) {
    emit('click', event);
  }
};
</script>

<template>
  <button
    :style="buttonStyle"
    :disabled="disabled || loading"
    @click="handleClick"
    @mouseenter="isHover = true"
    @mouseleave="
      isHover = false;
      isActive = false;
    "
    @mousedown="isActive = true"
    @mouseup="isActive = false"
  >
    <i v-if="loading" class="fa-solid fa-spinner fa-spin"></i>
    <i v-else-if="icon" :class="icon"></i>
    <slot></slot>
  </button>
</template>
